module RefModule(
  input clk,
  input rst,
  output [m-1:0] out
);parameter n = 4; // number of states
parameter m = 2; // number of output signals

reg [n-1:0] pipeline_reg;
reg [m-1:0] out_reg;

// Define the output signals as functions of the current pipeline_reg
always @ (pipeline_reg) begin
  case (pipeline_reg)
    0: out_reg = {1'b0, 1'b0};
    1: out_reg = {1'b0, 1'b1};
    2: out_reg = {1'b1, 1'b0};
    3: out_reg = {1'b1, 1'b1};
  endcase
end

// Define the pipeline_reg transitions
always @ (posedge clk, posedge rst) begin
  if (rst) begin
    pipeline_reg <= 0;
  end else begin
    case (pipeline_reg)
      0: pipeline_reg <= 1;
      1: pipeline_reg <= 2;
      2: pipeline_reg <= 3;
      3: pipeline_reg <= 0;
    endcase
  end
end

// Assign the output signals
assign out = out_reg;

endmodule
